module gray_code_counter_2bit(
    input clk,
    input rst,

    output reg [1:0] gray_q
);

reg [1:0] obf_binary_q;  // Internal binary counter

// Gray Code Counter logic
always @(posedge clk) begin
    if (rst)
        obf_binary_q <= 2'b00;
    else
        obf_binary_q <= obf_binary_q + 1;
end

// Convert binary counter to Gray code
always @(obf_binary_q) begin
    gray_q = obf_binary_q ^ (obf_binary_q >> 1);
end

endmodule
